import "../styles/UploadForm.css";
import { useState, useRef } from "react";
import ResultCard from "./ResultCard";
import { useDropzone } from "react-dropzone";

function UploadForm() {
  const [image, setImage] = useState(null);
  const [mask, setMask] = useState(null);
  const [weight, setWeight] = useState("");
  const [result, setResult] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const [maskPreview, setMaskPreview] = useState(null);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const imageInputRef = useRef(null);
  const maskInputRef = useRef(null);

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!image || !mask || !weight) {
      setError("Please upload image, mask and weight");
      return;
    }

    setError("");
    setLoading(true);

    setTimeout(() => {
      setResult({
        length_cm: 28.4,
        thickness_cm: 6.2,
        perimeter_cm: 52.8,
        area_cm2: 135.2,
        volume_proxy_cm3: 840.1,
        predicted_weight_g: 1250,
      });

      setLoading(false);
    }, 2000);
  };

  const removeImage = () => {
    setImage(null);
    setImagePreview(null);

    if (imageInputRef.current) {
      imageInputRef.current.value = "";
    }
  };

  const removeMask = () => {
    setMask(null);
    setMaskPreview(null);

    if (maskInputRef.current) {
      maskInputRef.current.value = "";
    }
  };
  const onDropImage = (acceptedFiles) => {
  const file = acceptedFiles[0];

  if (file) {
    setImage(file);
    setImagePreview(URL.createObjectURL(file));
  }
};

const {
  getRootProps: getImageRootProps,
  getInputProps: getImageInputProps,
} = useDropzone({
  onDrop: onDropImage,
  accept: {
    "image/*": [],
  },
  multiple: false,
});

  return (
    <div className="container">
      <form onSubmit={handleSubmit}>
        <div {...getImageRootProps()} className="dropzone">
  <input {...getImageInputProps()} />

  <p>🐟 Drag & Drop Fish Image Here</p>
  <span>or click to browse</span>
</div>

        <label>Fish Mask</label>
        <input
          ref={maskInputRef}
          type="file"
          accept="image/*"
          onChange={(e) => {
            const file = e.target.files[0];

            if (file) {
              setMask(file);
              setMaskPreview(URL.createObjectURL(file));
            }
          }}
        />

        <label>Actual Weight (g)</label>
        <input
          type="number"
          value={weight}
          onChange={(e) => setWeight(e.target.value)}
        />

        <div className="preview-container">
          {imagePreview && (
            <div className="preview-card">
              <h4>Fish Image</h4>
              <img src={imagePreview} alt="Fish" />

              <button
                type="button"
                className="remove-btn"
                onClick={removeImage}
              >
                Remove
              </button>
            </div>
          )}

          {maskPreview && (
            <div className="preview-card">
              <h4>Fish Mask</h4>
              <img src={maskPreview} alt="Mask" />

              <button
                type="button"
                className="remove-btn"
                onClick={removeMask}
              >
                Remove
              </button>
            </div>
          )}
        </div>

        {error && <p className="error">{error}</p>}

        <button type="submit">
          {loading ? "Estimating..." : "Estimate Weight"}
        </button>
      </form>

      <ResultCard result={result} />
    </div>
  );
}

export default UploadForm;
